SELECT ?ruler ?rulerLabel WHERE {
  ?ruler wdt:P35 wd:Q12560.
  ?ruler p:P35 ?statement.
  ?statement ps:P35 wd:Q12560.
  ?statement pq:P580 ?start.
  ?statement pq:P582 ?end.
  FILTER(?start < "1600-01-01T00:00:00Z"^^xsd:dateTime && ?end > "1500-01-01T00:00:00Z"^^xsd:dateTime)
  OPTIONAL { ?ruler rdfs:label ?rulerLabel. FILTER(LANG(?rulerLabel) = "en") }
}

